import { PDFDocument, StandardFonts, rgb } from 'pdf-lib';
import { Resend } from 'resend';

const HR_EMAIL = process.env.HR_EMAIL || 'foodandbooze@gmail.com';
const resend = new Resend(process.env.RESEND_API_KEY);

const LOGO_B64 = '';

// ── helpers ──────────────────────────────────────────────────────────────────

async function embedLogo(doc, page, x, y, maxW=160) {
  try {
    const imgBytes = Buffer.from(LOGO_B64, 'base64');
    const img = await doc.embedPng(imgBytes);
    const { width, height } = img.scale(1);
    const scale = maxW / width;
    page.drawImage(img, { x, y: y - height*scale, width: width*scale, height: height*scale });
    return height * scale;
  } catch(e) { return 0; }
}

function addText(page, txt, x, y, font, size, color=rgb(0,0,0)) {
  if (!txt) return;
  page.drawText(String(txt), { x, y, size, font, color });
}

function field(page, label, value, x, y, labelFont, valueFont, labelSz=8, valueSz=11) {
  addText(page, label.toUpperCase(), x, y, labelFont, labelSz, rgb(0.5,0.5,0.5));
  addText(page, value || '—', x, y - 14, valueFont, valueSz, rgb(0,0,0));
  return y - 32;
}

function sectionHeader(page, title, y, font, pageW) {
  addText(page, title.toUpperCase(), 40, y, font, 9, rgb(0.91,0.45,0.04));
  page.drawLine({ start:{x:40,y:y-3}, end:{x:pageW-40,y:y-3}, thickness:0.8, color:rgb(0.91,0.45,0.04) });
  return y - 18;
}

function twoCol(page, items, startY, labelFont, valueFont, pageW) {
  let y = startY;
  const col1x = 40, col2x = pageW/2 + 10;
  for (let i = 0; i < items.length; i += 2) {
    const [l1, v1] = items[i];
    const [l2, v2] = items[i+1] || ['',''];
    addText(page, l1.toUpperCase(), col1x, y, labelFont, 8, rgb(0.5,0.5,0.5));
    if (l2) addText(page, l2.toUpperCase(), col2x, y, labelFont, 8, rgb(0.5,0.5,0.5));
    addText(page, v1||'—', col1x, y-13, valueFont, 10);
    if (l2) addText(page, v2||'—', col2x, y-13, valueFont, 10);
    y -= 30;
  }
  return y;
}

// ── Application PDF ──────────────────────────────────────────────────────────

async function buildApplicationPDF(d) {
  const doc = await PDFDocument.create();
  const font = await doc.embedFont(StandardFonts.Helvetica);
  const bold = await doc.embedFont(StandardFonts.HelveticaBold);

  let page = doc.addPage([612, 792]);
  const W = 612;
  let y = 760;

  // Logo + header
  const logoH = await embedLogo(doc, page, 40, y, 150);
  addText(page, 'DRIVER EMPLOYMENT APPLICATION', 210, y - 10, bold, 15, rgb(0.1,0.1,0.1));
  addText(page, 'Pale Horse Asphalt Engineering', 210, y - 28, font, 10, rgb(0.5,0.5,0.5));
  addText(page, '19256 California Hwy 99, Acampo CA 95220', 210, y - 42, font, 9, rgb(0.6,0.6,0.6));
  y -= Math.max(logoH, 60) + 12;
  page.drawLine({ start:{x:40,y}, end:{x:W-40,y}, thickness:1.5, color:rgb(0.91,0.45,0.04) });
  y -= 16;

  addText(page, `${d.firstName} ${d.lastName}`, 40, y, bold, 18);
  addText(page, `Applied: ${d.appDate}   |   Position: ${d.position}`, 40, y-18, font, 9, rgb(0.5,0.5,0.5));
  y -= 44;

  // Personal
  y = sectionHeader(page, 'Personal Information', y, bold, W);
  y = twoCol(page, [
    ['Full Name', `${d.firstName} ${d.lastName}`],
    ['SSN', d.ssn],
    ['Date of Birth', d.dob],
    ['Phone', d.phone],
    ['Email', d.email],
    ['Work Eligible (US)', d.eligible],
    ['Address', `${d.street}, ${d.city}, ${d.state} ${d.zip}`],
    ['Pay Expected', d.payExpected],
    ['Date Available', d.dateAvail],
    ['Previously Employed Here', d.workedBefore],
  ], y, font, bold, W);
  y -= 8;

  // License
  y = sectionHeader(page, "Driver's License", y, bold, W);
  y = twoCol(page, [
    ['DL Number', d.dlNum],
    ['State / Class', `${d.dlState} — Class ${d.dlClass}`],
    ['Expiry', d.dlExp],
    ['Endorsements', d.endorsements || 'None'],
    ['States Operated', d.statesOp],
    ['DL Suspended/Revoked', d.dlIssue],
    ['CDL Violations (12 mo)', d.cdlViol],
    ['Years CDL Experience', d.yearsExp],
  ], y, font, bold, W);
  y -= 8;

  const addEmployer = (num, name, addr, city, st, zip, phone, sup, title, from, to, reason, contact) => {
    if (!name) return;
    if (y < 120) { page = doc.addPage([612,792]); y = 750; }
    y = sectionHeader(page, `Employer ${num}`, y, bold, W);
    y = twoCol(page, [
      ['Company', name],
      ['Phone', phone],
      ['Address', `${addr}, ${city}, ${st} ${zip}`],
      ['Supervisor', sup],
      ['Position', title],
      ['Dates', `${from} – ${to}`],
      ['Reason Left', reason],
      ['May Contact', contact],
    ], y, font, bold, W);
    y -= 8;
  };

  addEmployer(1, d.e1name, d.e1addr, d.e1city, d.e1state, d.e1zip, d.e1phone, d.e1supervisor, d.e1title, d.e1from, d.e1to, d.e1reason, d.e1mayContact);
  addEmployer(2, d.e2name, d.e2addr, d.e2city, d.e2state, d.e2zip, d.e2phone, d.e2supervisor, d.e2title, d.e2from, d.e2to, d.e2reason, d.e2mayContact);
  addEmployer(3, d.e3name, d.e3addr, d.e3city, d.e3state, d.e3zip, d.e3phone, d.e3supervisor, d.e3title, d.e3from, d.e3to, d.e3reason, d.e3mayContact);

  if (y < 200) { page = doc.addPage([612,792]); y = 750; }

  // Experience
  y = sectionHeader(page, 'Driving Experience & Safety', y, bold, W);
  y = twoCol(page, [
    ['Vehicles Operated', d.vehicles || 'Not specified'],
    ['Approx Miles (3 yr)', d.miles],
    ['Years CDL Experience', d.yearsExp],
    ['Accidents (3 yr)', d.accidents === 'none' ? 'None' : d.accidentDetails || d.accidents],
    ['Violations (3 yr)', d.violations === 'none' ? 'None' : d.violationDetails || d.violations],
    ['Drug/Alcohol Test Positive', d.drugTest],
    ['Test Refusal', d.refusedTest],
    ...(d.clearinghouseConsent ? [['FMCSA Clearinghouse Consent', d.clearinghouseConsent === 'yes' ? 'Yes — Consented' : 'No — Refused']] : []),
    ...(d.hosLog && d.hosLog.length ? [['HOS 7-Day Log', d.hosLog.map(r => `${r.date}: ${r.offDuty ? 'Off Duty' : (r.hours != null ? r.hours + 'h' : '—')}`).join('  ')]] : []),
    ['', ''],
  ], y, font, bold, W);
  y -= 8;

  // Emergency
  y = sectionHeader(page, 'Emergency Contact', y, bold, W);
  y = twoCol(page, [
    ['Name', d.ecName],
    ['Relationship', d.ecRel],
    ['Phone', d.ecPhone],
    ['', ''],
  ], y, font, bold, W);
  y -= 8;

  // Certification
  if (y < 160) { page = doc.addPage([612,792]); y = 750; }
  y = sectionHeader(page, 'Certification', y, bold, W);
  addText(page, 'I certify that all information is true and complete. False statements may result in refusal of employment or discharge.', 40, y, font, 8, rgb(0.4,0.4,0.4));
  y -= 20;
  addText(page, 'Printed Name:', 40, y, font, 8, rgb(0.5,0.5,0.5));
  addText(page, d.sigName, 120, y, bold, 11);
  addText(page, 'Date:', 380, y, font, 8, rgb(0.5,0.5,0.5));
  addText(page, d.sigDate, 410, y, bold, 11);
  y -= 24;
  // Embed drawn signature
  if (d.signature) {
    try {
      const sigBytes = Buffer.from(d.signature, 'base64');
      const sigImg = await doc.embedPng(sigBytes);
      const { width: sw, height: sh } = sigImg.scale(1);
      const sigW = Math.min(200, sw);
      const sigH = (sh / sw) * sigW;
      page.drawImage(sigImg, { x: 40, y: y - sigH, width: sigW, height: sigH });
      y -= sigH + 8;
    } catch(e) { y -= 8; }
  }
  page.drawLine({ start:{x:40,y}, end:{x:280,y}, thickness:0.5, color:rgb(0.3,0.3,0.3) });
  addText(page, 'Applicant Signature', 40, y-12, font, 7, rgb(0.6,0.6,0.6));

  // Page numbers
  const total = doc.getPageCount();
  for (let i = 0; i < total; i++) {
    const pg = doc.getPage(i);
    addText(pg, `Page ${i+1} of ${total}  —  Pale Horse Asphalt Engineering  —  Confidential`, 40, 18, font, 7, rgb(0.7,0.7,0.7));
  }

  return doc.save();
}

// ── W-4 ──────────────────────────────────────────────────────────────────────

async function buildW4(d) {
  const doc = await PDFDocument.create();
  const font = await doc.embedFont(StandardFonts.Helvetica);
  const bold = await doc.embedFont(StandardFonts.HelveticaBold);
  const page = doc.addPage([612, 792]);
  const W = 612;
  let y = 760;

  await embedLogo(doc, page, 40, y, 120);
  addText(page, "Form W-4 — Employee's Withholding Certificate", 175, y-10, bold, 13);
  addText(page, 'Department of the Treasury — Internal Revenue Service    2026', 175, y-26, font, 9, rgb(0.4,0.4,0.4));
  y -= 60;
  page.drawLine({ start:{x:40,y}, end:{x:W-40,y}, thickness:1, color:rgb(0.91,0.45,0.04) });
  y -= 20;

  addText(page, 'STEP 1 — PERSONAL INFORMATION', 40, y, bold, 10, rgb(0.91,0.45,0.04));
  y -= 20;
  y = twoCol(page, [
    ['First Name', d.firstName],
    ['Last Name', d.lastName],
    ['Social Security Number', d.ssn],
    ['Date of Birth', d.dob],
    ['Street Address', d.street],
    [''],
    ['City', d.city],
    ['State / ZIP', `${d.state} ${d.zip}`],
  ], y, font, bold, W);
  y -= 8;

  addText(page, 'STEP 1c — FILING STATUS', 40, y, bold, 10, rgb(0.91,0.45,0.04));
  y -= 20;
  const statuses = ['Single or Married Filing Separately','Married Filing Jointly','Head of Household'];
  for (const s of statuses) {
    const checked = d.w4FilingStatus === s;
    addText(page, `${checked ? '[X]' : '[ ]'}  ${s}`, 40, y, checked ? bold : font, 10, checked ? rgb(0,0,0) : rgb(0.3,0.3,0.3));
    y -= 18;
  }
  y -= 12;

  addText(page, 'STEP 2 — MULTIPLE JOBS OR SPOUSE WORKS', 40, y, bold, 10, rgb(0.91,0.45,0.04));
  y -= 20;
  const mj = d.w4MultiJob === 'yes';
  addText(page, `${mj ? '[X]' : '[ ]'}  (c) Two jobs total — check this box (and do the same on other job W-4)`, 40, y, mj ? bold : font, 10);
  y -= 30;

  addText(page, 'STEP 3 — CLAIM DEPENDENTS', 40, y, bold, 10, rgb(0.91,0.45,0.04));
  y -= 20;
  const childAmt = (parseInt(d.w4Children)||0) * 2000;
  const otherAmt = (parseInt(d.w4OtherDep)||0) * 500;
  const totalDep = childAmt + otherAmt;
  addText(page, `Qualifying children under 17 x $2,000:  $${childAmt.toLocaleString()}`, 40, y, font, 10); y -= 18;
  addText(page, `Other dependents x $500:  $${otherAmt.toLocaleString()}`, 40, y, font, 10); y -= 18;
  addText(page, `Total:  $${totalDep.toLocaleString()}`, 40, y, bold, 10); y -= 30;

  addText(page, 'STEP 4 — OPTIONAL ADJUSTMENTS', 40, y, bold, 10, rgb(0.91,0.45,0.04));
  y -= 20;
  addText(page, `(a) Other income not from jobs:  $${d.w4OtherIncome||'0'}`, 40, y, font, 10); y -= 18;
  addText(page, `(b) Deductions:  $${d.w4Deductions||'0'}`, 40, y, font, 10); y -= 18;
  addText(page, `(c) Extra withholding per pay period:  $${d.w4Extra||'0'}`, 40, y, font, 10); y -= 30;

  addText(page, 'STEP 5 — SIGN HERE', 40, y, bold, 10, rgb(0.91,0.45,0.04));
  y -= 16;
  addText(page, 'Under penalties of perjury, I declare this certificate is correct to the best of my knowledge.', 40, y, font, 8, rgb(0.4,0.4,0.4));
  y -= 24;
  addText(page, 'Employee Signature:', 40, y, font, 8, rgb(0.5,0.5,0.5));
  page.drawLine({ start:{x:150,y:y-2}, end:{x:360,y:y-2}, thickness:0.6, color:rgb(0.3,0.3,0.3) });
  addText(page, 'Date:', 370, y, font, 8, rgb(0.5,0.5,0.5));
  if (d.sigDate) addText(page, d.sigDate, 400, y, font, 10);
  page.drawLine({ start:{x:400,y:y-2}, end:{x:560,y:y-2}, thickness:0.6, color:rgb(0.3,0.3,0.3) });
  if (d.signature) {
    try {
      const sigBytes = Buffer.from(d.signature, 'base64');
      const sigImg = await doc.embedPng(sigBytes);
      const {width:sw,height:sh} = sigImg.scale(1);
      const sigW = Math.min(180,sw), sigH = (sh/sw)*sigW;
      page.drawImage(sigImg, {x:150, y:y-sigH, width:sigW, height:sigH});
      y -= sigH + 8;
    } catch(e) { y -= 28; }
  } else { y -= 28; }

  addText(page, "Employer: Pale Horse Asphalt Engineering  |  19256 California Hwy 99, Acampo CA 95220", 40, y, font, 9);
  y -= 16;
  addText(page, "First Date of Employment: ________________    EIN: ________________", 40, y, font, 9);
  y -= 30;

  addText(page, 'Pre-filled: Name and address only. Employee must complete filing status, steps 2–5, and sign.', 40, y, font, 7, rgb(0.6,0.6,0.6));
  addText(page, 'See full instructions at irs.gov/w4', 40, y-12, font, 7, rgb(0.6,0.6,0.6));

  return doc.save();
}

