// ── Direct Deposit page ──────────────────────────────────────────────────────

async function buildDirectDeposit(d) {
  const doc = await PDFDocument.create();
  const font = await doc.embedFont(StandardFonts.Helvetica);
  const bold = await doc.embedFont(StandardFonts.HelveticaBold);
  const page = doc.addPage([612, 792]);
  const W = 612;
  let y = 760;

  await embedLogo(doc, page, 40, y, 120);
  addText(page, 'Direct Deposit Authorization', 175, y-10, bold, 14);
  addText(page, `${d.firstName} ${d.lastName}  —  ${d.appDate}`, 175, y-28, font, 9, rgb(0.5,0.5,0.5));
  y -= 60;
  page.drawLine({ start:{x:40,y}, end:{x:W-40,y}, thickness:1, color:rgb(0.91,0.45,0.04) });
  y -= 24;

  addText(page, 'I authorize Pale Horse Asphalt Engineering to deposit my pay directly to the account below.', 40, y, font, 9, rgb(0.4,0.4,0.4));
  y -= 30;

  y = twoCol(page, [
    ['Employee Name', `${d.firstName} ${d.lastName}`],
    ['SSN', d.ssn],
    ['Bank Name', d.bankName],
    ['Account Type', d.acctType ? d.acctType.charAt(0).toUpperCase()+d.acctType.slice(1) : ''],
    ['Routing Number', d.routingNum],
    ['Account Number', d.accountNum],
  ], y, font, bold, W);
  y -= 24;

  addText(page, 'Employee Signature:', 40, y, font, 8, rgb(0.5,0.5,0.5));
  page.drawLine({ start:{x:150,y:y-2}, end:{x:360,y:y-2}, thickness:0.6, color:rgb(0.3,0.3,0.3) });
  addText(page, 'Date:', 370, y, font, 8, rgb(0.5,0.5,0.5));
  if (d.sigDate) addText(page, d.sigDate, 400, y, font, 10);
  page.drawLine({ start:{x:400,y:y-2}, end:{x:560,y:y-2}, thickness:0.6, color:rgb(0.3,0.3,0.3) });
  if (d.signature) {
    try {
      const sigBytes = Buffer.from(d.signature, 'base64');
      const sigImg = await doc.embedPng(sigBytes);
      const { width: sw, height: sh } = sigImg.scale(1);
      const sigW = Math.min(180, sw);
      const sigH = (sh/sw)*sigW;
      page.drawImage(sigImg, { x: 150, y: y-sigH, width: sigW, height: sigH });
      y -= sigH + 8;
    } catch(e) { y -= 28; }
  } else { y -= 28; }

  addText(page, 'Attach a voided check or bank letter to verify routing and account numbers.', 40, y-10, font, 8, rgb(0.6,0.6,0.6));

  return doc.save();
}

// ── ID Photos page ────────────────────────────────────────────────────────────

async function buildIDPage(d) {
  const doc = await PDFDocument.create();
  const font = await doc.embedFont(StandardFonts.Helvetica);
  const bold = await doc.embedFont(StandardFonts.HelveticaBold);
  const page = doc.addPage([612, 792]);
  const W = 612;
  let y = 760;

  await embedLogo(doc, page, 40, y, 120);
  addText(page, 'Identity Documents', 175, y-10, bold, 14);
  addText(page, `${d.firstName} ${d.lastName}  —  ${d.appDate}`, 175, y-28, font, 9, rgb(0.5,0.5,0.5));
  y -= 60;
  page.drawLine({ start:{x:40,y}, end:{x:W-40,y}, thickness:1, color:rgb(0.91,0.45,0.04) });
  y -= 16;

  const embedImg = async (b64, label, yPos, isPdf) => {
    if (!b64) return yPos;
    try {
      const bytes = Buffer.from(b64, 'base64');
      addText(page, label, 40, yPos, bold, 9, rgb(0.91,0.45,0.04));
      yPos -= 12;
      if (isPdf) {
        const [embPage] = await doc.embedPdf(bytes, [0]);
        const { width: pw, height: ph } = embPage;
        const scale = Math.min(240/pw, 320/ph);
        const w = pw*scale, h = ph*scale;
        page.drawPage(embPage, { x: 40, y: yPos - h, width: w, height: h });
        return yPos - h - 16;
      }
      const img = await doc.embedJpg(bytes).catch(() => doc.embedPng(bytes));
      const { width: iw, height: ih } = img.scale(1);
      const scale = Math.min(240/iw, 160/ih);
      const w = iw*scale, h = ih*scale;
      page.drawImage(img, { x: 40, y: yPos - h, width: w, height: h });
      return yPos - h - 16;
    } catch(e) { return yPos; }
  };

  addText(page, "DRIVER'S LICENSE", 40, y, bold, 10, rgb(0,0,0)); y -= 16;
  y = await embedImg(d.dlFront, 'Front', y);
  y = await embedImg(d.dlBack, 'Back', y);
  y -= 8;

  const id2Label = d.id2Type === 'ss' ? 'Social Security Card' : d.id2Type === 'passport' ? 'Passport' : 'Birth Certificate';
  addText(page, id2Label.toUpperCase(), 40, y, bold, 10, rgb(0,0,0)); y -= 16;
  y = await embedImg(d.id2, id2Label, y, d.id2IsPdf);

  if (d.medCard) {
    y -= 8;
    addText(page, 'DOT MEDICAL CARD', 40, y, bold, 10, rgb(0,0,0)); y -= 16;
    y = await embedImg(d.medCard, "Medical Examiner's Certificate", y, d.medCardIsPdf);
  }

  addText(page, 'Documents verified by employer per I-9 requirements.', 40, 30, font, 7, rgb(0.6,0.6,0.6));

  return doc.save();
}

// ── merge ─────────────────────────────────────────────────────────────────────

async function mergePDFs(pdfBytes) {
  const merged = await PDFDocument.create();
  for (const bytes of pdfBytes) {
    const src = await PDFDocument.load(bytes);
    const pages = await merged.copyPages(src, src.getPageIndices());
    pages.forEach(p => merged.addPage(p));
  }
  return merged.save();
}

// ── handler ───────────────────────────────────────────────────────────────────

export const config = { api: { bodyParser: { sizeLimit: '12mb' } } };

export default async function handler(req, res) {
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });
  const d = req.body;
  if (!d || !d.firstName || !d.lastName) return res.status(400).json({ error: 'Missing required fields' });

  try {
    const [appPdf, w4Pdf, de4Pdf, i9Pdf, ddPdf, idPdf] = await Promise.all([
      buildApplicationPDF(d),
      buildW4(d),
      buildDE4(d),
      buildI9(d),
      buildDirectDeposit(d),
      buildIDPage(d),
    ]);

    const combined = await mergePDFs([appPdf, w4Pdf, de4Pdf, i9Pdf, ddPdf, idPdf]);
    const b64 = Buffer.from(combined).toString('base64');
    const filename = `${d.lastName}_${d.firstName}_DriverApp_${(d.appDate||'').replace(/\//g,'-')}.pdf`;

    await resend.emails.send({
      from: 'Driver Application <onboarding@resend.dev>',
      to: [HR_EMAIL],
      subject: `New Driver Application — ${d.firstName} ${d.lastName}`,
      html: `
        <h2>New Driver Application</h2>
        <p><b>Name:</b> ${d.firstName} ${d.lastName}</p>
        <p><b>Position:</b> ${d.position}</p>
        <p><b>Phone:</b> ${d.phone}</p>
        <p><b>Email:</b> ${d.email}</p>
        <p><b>DL:</b> ${d.dlNum} ${d.dlState} Class ${d.dlClass} exp ${d.dlExp}</p>
        <p><b>Date:</b> ${d.appDate}</p>
        <hr>
        <p>Attached: Application + W-4 + DE-4 + I-9 (5 pages)</p>
        <p><i>Still needed: Road test, MVR, drug screen, medical card</i></p>
      `,
      attachments: [{ filename, content: b64 }],
    });

    return res.status(200).json({ ok: true });
  } catch(err) {
    console.error(err);
    return res.status(500).json({ error: err.message || 'Internal server error' });
  }
}
